tool_calls:
awk -F',' '
  # Load departments.csv into a lookup map
  NR==FNR {
    if (NR > 1) dept[$1] = $2   # dept[department_id] = department_name
    next
  }
  # Process employees.csv
  FNR == 1 { print "name,department_name,salary"; next }
  { print $1 "," dept[$2] "," $3 }
' /data/departments.csv /data/employees.csv | tee /data/report.csv

